   172→uint64_t HeadersByteSizeFormatter::extractHeadersByteSize(
   173→    const Http::RequestHeaderMap& request_headers, const Http::ResponseHeaderMap& response_headers,
   174→    const Http::ResponseTrailerMap& response_trailers) const {
   175→  switch (header_type_) {
   176→  case HeaderType::RequestHeaders:
   177→    return request_headers.byteSize();
   178→  case HeaderType::ResponseHeaders:
   179→    return response_headers.byteSize();
   180→  case HeaderType::ResponseTrailers:
   181→    return response_trailers.byteSize();
   182→  }
   183→  PANIC_DUE_TO_CORRUPT_ENUM;
   184→}
