   235→GrpcStatusFormatter::GrpcStatusFormatter(const std::string& main_header,
   236→                                         const std::string& alternative_header,
   237→                                         absl::optional<size_t> max_length, Format format)
   238→    : HeaderFormatter(main_header, alternative_header, max_length), format_(format) {}
