   423→FormatterProviderPtr HttpBuiltInCommandParser::parse(const std::string& command,
   424→                                                     const std::string& subcommand,
   425→                                                     absl::optional<size_t>& max_length) const {
   426→  const FormatterProviderLookupTbl& providers = getKnownFormatters();
   427→
   428→  auto it = providers.find(command);
   429→
   430→  if (it == providers.end()) {
   431→    return nullptr;
   432→  }
   433→
   434→  // Check flags for the command.
   435→  THROW_IF_NOT_OK(
   436→      CommandSyntaxChecker::verifySyntax((*it).second.first, command, subcommand, max_length));
   437→
   438→  // Create a pointer to the formatter by calling a function
   439→  // associated with formatter's name.
   440→  return (*it).second.second(subcommand, max_length);
   441→}
   442→
   443→REGISTER_BUILT_IN_COMMAND_PARSER(HttpFormatterContext, HttpBuiltInCommandParser);
   444→
   445→static const std::string DEFAULT_FORMAT =
   446→    "[%START_TIME%] \"%REQ(:METHOD)% %REQ(X-ENVOY-ORIGINAL-PATH?:PATH)% %PROTOCOL%\" "
   447→    "%RESPONSE_CODE% %RESPONSE_FLAGS% %BYTES_RECEIVED% %BYTES_SENT% %DURATION% "
   448→    "%RESP(X-ENVOY-UPSTREAM-SERVICE-TIME)% "
   449→    "\"%REQ(X-FORWARDED-FOR)%\" \"%REQ(USER-AGENT)%\" \"%REQ(X-REQUEST-ID)%\" "
   450→    "\"%REQ(:AUTHORITY)%\" \"%UPSTREAM_HOST%\"\n";
   451→
   452→FormatterPtr HttpSubstitutionFormatUtils::defaultSubstitutionFormatter() {
   453→  return std::make_unique<Envoy::Formatter::FormatterImpl>(DEFAULT_FORMAT, false);
   454→}
