   308→  StreamInfoFormatterBase(const std::string& command, const std::string& sub_command = "",
   309→                          absl::optional<size_t> max_length = absl::nullopt) {
   310→
   311→    const auto& formatters = getKnownStreamInfoFormatterProviders();
   312→
   313→    auto it = formatters.find(command);
   314→
   315→    if (it == formatters.end()) {
   316→      throwEnvoyExceptionOrPanic(fmt::format("Not supported field in StreamInfo: {}", command));
   317→    }
   318→
   319→    // Check flags for the command.
   320→    THROW_IF_NOT_OK(
   321→        CommandSyntaxChecker::verifySyntax((*it).second.first, command, sub_command, max_length));
   322→
   323→    // Create a pointer to the formatter by calling a function
   324→    // associated with formatter's name.
   325→    formatter_ = (*it).second.second(sub_command, max_length);
   326→  }
