    25→/**
    26→ * Access log format parser.
    27→ */
    28→class SubstitutionFormatParser {
    29→public:
    30→  template <class FormatterContext = HttpFormatterContext>
    31→  static std::vector<FormatterProviderBasePtr<FormatterContext>>
    32→  parse(const std::string& format,
    33→        const std::vector<CommandParserBasePtr<FormatterContext>>& command_parsers = {}) {
    34→    std::string current_token;
    35→    std::vector<FormatterProviderBasePtr<FormatterContext>> formatters;
    36→
    37→    for (size_t pos = 0; pos < format.size(); ++pos) {
    38→      if (format[pos] != '%') {
    39→        current_token += format[pos];
    40→        continue;
    41→      }
    42→
    43→      // escape '%%'
    44→      if (format.size() > pos + 1) {
    45→        if (format[pos + 1] == '%') {
    46→          current_token += '%';
    47→          pos++;
    48→          continue;
    49→        }
    50→      }
    51→
    52→      if (!current_token.empty()) {
    53→        formatters.emplace_back(FormatterProviderBasePtr<FormatterContext>{
    54→            new PlainStringFormatterBase<FormatterContext>(current_token)});
    55→        current_token = "";
    56→      }
    57→
    58→      std::smatch m;
    59→      const std::string search_space = std::string(format.substr(pos));
    60→      if (!std::regex_search(search_space, m, commandWithArgsRegex())) {
    61→        throwEnvoyExceptionOrPanic(
    62→            fmt::format("Incorrect configuration: {}. Couldn't find valid command at position {}",
    63→                        format, pos));
    64→      }
    65→
    66→      const std::string match = m.str(0);
    67→      // command is at at index 1.
    68→      const std::string command = m.str(1);
    69→      // subcommand is at index 2.
    70→      const std::string subcommand = m.str(2);
    71→      // optional length is at index 3. If present, validate that it is valid integer.
    72→      absl::optional<size_t> max_length;
    73→      if (m.str(3).length() != 0) {
    74→        size_t length_value;
    75→        if (!absl::SimpleAtoi(m.str(3), &length_value)) {
    76→          throwEnvoyExceptionOrPanic(absl::StrCat("Length must be an integer, given: ", m.str(3)));
    77→        }
    78→        max_length = length_value;
    79→      }
    80→      std::vector<std::string> path;
    81→
    82→      const size_t command_end_position = pos + m.str(0).length() - 1;
    83→
    84→      bool added = false;
    85→
    86→      // First, try the built-in command parsers.
    87→      for (const auto& cmd : BuiltInCommandParsersBase<FormatterContext>::commandParsers()) {
    88→        auto formatter = cmd->parse(command, subcommand, max_length);
    89→        if (formatter) {
    90→          formatters.push_back(std::move(formatter));
    91→          added = true;
    92→          break;
    93→        }
    94→      }
    95→
    96→      // Next, try the command parsers provided by the user.
    97→      if (!added) {
    98→        for (const auto& cmd : command_parsers) {
    99→          auto formatter = cmd->parse(command, subcommand, max_length);
   100→          if (formatter) {
   101→            formatters.push_back(std::move(formatter));
   102→            added = true;
   103→            break;
   104→          }
   105→        }
   106→      }
   107→
   108→      if (!added) {
   109→        // Finally, try the context independent formatters.
   110→        formatters.emplace_back(FormatterProviderBasePtr<FormatterContext>{
   111→            new StreamInfoFormatterBase<FormatterContext>(command, subcommand, max_length)});
   112→      }
   113→
   114→      pos = command_end_position;
   115→    }
   116→
   117→    if (!current_token.empty() || format.empty()) {
   118→      // Create a PlainStringFormatter with the final string literal. If the format string
   119→      // was empty, this creates a PlainStringFormatter with an empty string.
   120→      formatters.emplace_back(FormatterProviderBasePtr<FormatterContext>{
   121→          new PlainStringFormatterBase<FormatterContext>(current_token)});
   122→    }
   123→
   124→    return formatters;
   125→  }
   126→
   127→private:
   128→  static const std::regex& commandWithArgsRegex();
   129→};
