   131→inline constexpr absl::string_view DefaultUnspecifiedValueStringView = "-";
   132→
   133→/**
   134→ * Composite formatter implementation.
   135→ */
   136→template <class FormatterContext> class FormatterBaseImpl : public FormatterBase<FormatterContext> {
   137→public:
   138→  using CommandParsers = std::vector<CommandParserBasePtr<FormatterContext>>;
   139→
   140→  FormatterBaseImpl(const std::string& format, bool omit_empty_values = false)
   141→      : empty_value_string_(omit_empty_values ? absl::string_view{}
   142→                                              : DefaultUnspecifiedValueStringView) {
   143→    providers_ = SubstitutionFormatParser::parse<FormatterContext>(format);
   144→  }
   145→  FormatterBaseImpl(const std::string& format, bool omit_empty_values,
   146→                    const CommandParsers& command_parsers)
   147→      : empty_value_string_(omit_empty_values ? absl::string_view{}
   148→                                              : DefaultUnspecifiedValueStringView) {
   149→    providers_ = SubstitutionFormatParser::parse<FormatterContext>(format, command_parsers);
   150→  }
   151→
   152→  // FormatterBase
   153→  std::string formatWithContext(const FormatterContext& context,
   154→                                const StreamInfo::StreamInfo& stream_info) const override {
   155→    std::string log_line;
   156→    log_line.reserve(256);
   157→
   158→    for (const auto& provider : providers_) {
   159→      const auto bit = provider->formatWithContext(context, stream_info);
   160→      log_line += bit.value_or(empty_value_string_);
   161→    }
   162→
   163→    return log_line;
   164→  }
   165→
   166→private:
   167→  const std::string empty_value_string_;
   168→  std::vector<FormatterProviderBasePtr<FormatterContext>> providers_;
   169→};
