   161→    }
   162→
   163→    return log_line;
   164→  }
   165→
   166→private:
   167→  const std::string empty_value_string_;
   168→  std::vector<FormatterProviderBasePtr<FormatterContext>> providers_;
   169→};
   170→
   171→// Helper classes for StructFormatter::StructFormatMapVisitor.
   172→template <class... Ts> struct StructFormatMapVisitorHelper : Ts... { using Ts::operator()...; };
   173→template <class... Ts> StructFormatMapVisitorHelper(Ts...) -> StructFormatMapVisitorHelper<Ts...>;
   174→
   175→/**
   176→ * An formatter for structured log formats, which returns a Struct proto that
   177→ * can be converted easily into multiple formats.
   178→ */
   179→template <class FormatterContext> class StructFormatterBase {
   180→public:
   181→  using CommandParsers = std::vector<CommandParserBasePtr<FormatterContext>>;
   182→  using PlainNumber = PlainNumberFormatterBase<FormatterContext>;
   183→  using PlainString = PlainStringFormatterBase<FormatterContext>;
   184→
   185→  StructFormatterBase(const ProtobufWkt::Struct& format_mapping, bool preserve_types,
   186→                      bool omit_empty_values, const CommandParsers& commands = {})
   187→      : omit_empty_values_(omit_empty_values), preserve_types_(preserve_types),
   188→        empty_value_(omit_empty_values_ ? std::string()
   189→                                        : std::string(DefaultUnspecifiedValueStringView)),
   190→        struct_output_format_(FormatBuilder(commands).toFormatMapValue(format_mapping)) {}
   191→
   192→  ProtobufWkt::Struct formatWithContext(const FormatterContext& context,
   193→                                        const StreamInfo::StreamInfo& info) const {
   194→    StructFormatMapVisitor visitor{
   195→        [&](const std::vector<FormatterProviderBasePtr<FormatterContext>>& providers) {
   196→          return providersCallback(providers, context, info);
   197→        },
   198→        [&, this](const StructFormatterBase::StructFormatMapWrapper& format_map) {
   199→          return structFormatMapCallback(format_map, visitor);
   200→        },
   201→        [&, this](const StructFormatterBase::StructFormatListWrapper& format_list) {
   202→          return structFormatListCallback(format_list, visitor);
   203→        },
   204→    };
   205→    return structFormatMapCallback(struct_output_format_, visitor).struct_value();
   206→  }
   207→
   208→private:
   209→  struct StructFormatMapWrapper;
   210→  struct StructFormatListWrapper;
   211→  using StructFormatValue =
   212→      absl::variant<const std::vector<FormatterProviderBasePtr<FormatterContext>>,
   213→                    const StructFormatMapWrapper, const StructFormatListWrapper>;
   214→  // Although not required for Struct/JSON, it is nice to have the order of
   215→  // properties preserved between the format and the log entry, thus std::map.
   216→  using StructFormatMap = std::map<std::string, StructFormatValue>;
   217→  using StructFormatMapPtr = std::unique_ptr<StructFormatMap>;
   218→  struct StructFormatMapWrapper {
   219→    StructFormatMapPtr value_;
   220→  };
   221→
   222→  using StructFormatList = std::list<StructFormatValue>;
   223→  using StructFormatListPtr = std::unique_ptr<StructFormatList>;
   224→  struct StructFormatListWrapper {
   225→    StructFormatListPtr value_;
   226→  };
   227→
   228→  using StructFormatMapVisitor = StructFormatMapVisitorHelper<
   229→      const std::function<ProtobufWkt::Value(
   230→          const std::vector<FormatterProviderBasePtr<FormatterContext>>&)>,
   231→      const std::function<ProtobufWkt::Value(const StructFormatterBase::StructFormatMapWrapper&)>,
   232→      const std::function<ProtobufWkt::Value(const StructFormatterBase::StructFormatListWrapper&)>>;
   233→
   234→  // Methods for building the format map.
   235→  class FormatBuilder {
   236→  public:
   237→    explicit FormatBuilder(const CommandParsers& commands) : commands_(commands) {}
   238→    std::vector<FormatterProviderBasePtr<FormatterContext>>
   239→    toFormatStringValue(const std::string& string_format) const {
   240→      return SubstitutionFormatParser::parse<FormatterContext>(string_format, commands_);
   241→    }
   242→    std::vector<FormatterProviderBasePtr<FormatterContext>>
   243→    toFormatNumberValue(double value) const {
   244→      std::vector<FormatterProviderBasePtr<FormatterContext>> formatters;
   245→      formatters.emplace_back(FormatterProviderBasePtr<FormatterContext>{new PlainNumber(value)});
   246→      return formatters;
   247→    }
   248→    StructFormatMapWrapper toFormatMapValue(const ProtobufWkt::Struct& struct_format) const {
   249→      auto output = std::make_unique<StructFormatMap>();
   250→      for (const auto& pair : struct_format.fields()) {
   251→        switch (pair.second.kind_case()) {
   252→        case ProtobufWkt::Value::kStringValue:
   253→          output->emplace(pair.first, toFormatStringValue(pair.second.string_value()));
   254→          break;
   255→
   256→        case ProtobufWkt::Value::kStructValue:
   257→          output->emplace(pair.first, toFormatMapValue(pair.second.struct_value()));
   258→          break;
   259→
   260→        case ProtobufWkt::Value::kListValue:
   261→          output->emplace(pair.first, toFormatListValue(pair.second.list_value()));
   262→          break;
   263→
   264→        case ProtobufWkt::Value::kNumberValue:
   265→          output->emplace(pair.first, toFormatNumberValue(pair.second.number_value()));
   266→          break;
   267→        default:
   268→          throwEnvoyExceptionOrPanic(
   269→              "Only string values, nested structs, list values and number values are "
   270→              "supported in structured access log format.");
   271→        }
   272→      }
   273→      return {std::move(output)};
   274→    }
   275→    StructFormatListWrapper
   276→    toFormatListValue(const ProtobufWkt::ListValue& list_value_format) const {
   277→      auto output = std::make_unique<StructFormatList>();
   278→      for (const auto& value : list_value_format.values()) {
   279→        switch (value.kind_case()) {
   280→        case ProtobufWkt::Value::kStringValue:
   281→          output->emplace_back(toFormatStringValue(value.string_value()));
   282→          break;
   283→
   284→        case ProtobufWkt::Value::kStructValue:
   285→          output->emplace_back(toFormatMapValue(value.struct_value()));
   286→          break;
   287→
   288→        case ProtobufWkt::Value::kListValue:
   289→          output->emplace_back(toFormatListValue(value.list_value()));
   290→          break;
   291→
   292→        case ProtobufWkt::Value::kNumberValue:
   293→          output->emplace_back(toFormatNumberValue(value.number_value()));
   294→          break;
   295→
   296→        default:
   297→          throwEnvoyExceptionOrPanic(
   298→              "Only string values, nested structs, list values and number values are "
   299→              "supported in structured access log format.");
   300→        }
   301→      }
   302→      return {std::move(output)};
   303→    }
   304→
   305→  private:
   306→    const CommandParsers& commands_;
   307→  };
   308→
   309→  // Methods for doing the actual formatting.
   310→  ProtobufWkt::Value
   311→  providersCallback(const std::vector<FormatterProviderBasePtr<FormatterContext>>& providers,
   312→                    const FormatterContext& context,
   313→                    const StreamInfo::StreamInfo& stream_info) const {
   314→    ASSERT(!providers.empty());
   315→    if (providers.size() == 1) {
   316→      const auto& provider = providers.front();
   317→      if (preserve_types_) {
   318→        return provider->formatValueWithContext(context, stream_info);
   319→      }
   320→
   321→      if (omit_empty_values_) {
   322→        return ValueUtil::optionalStringValue(provider->formatWithContext(context, stream_info));
   323→      }
   324→
   325→      const auto str = provider->formatWithContext(context, stream_info);
   326→      return ValueUtil::stringValue(str.value_or(empty_value_));
   327→    }
   328→    // Multiple providers forces string output.
   329→    std::string str;
   330→    for (const auto& provider : providers) {
   331→      const auto bit = provider->formatWithContext(context, stream_info);
   332→      str += bit.value_or(empty_value_);
   333→    }
   334→    return ValueUtil::stringValue(str);
   335→  }
   336→  ProtobufWkt::Value
   337→  structFormatMapCallback(const StructFormatterBase::StructFormatMapWrapper& format_map,
   338→                          const StructFormatMapVisitor& visitor) const {
   339→    ProtobufWkt::Struct output;
   340→    auto* fields = output.mutable_fields();
   341→    for (const auto& pair : *format_map.value_) {
   342→      ProtobufWkt::Value value = absl::visit(visitor, pair.second);
   343→      if (omit_empty_values_ && value.kind_case() == ProtobufWkt::Value::kNullValue) {
   344→        continue;
   345→      }
   346→      (*fields)[pair.first] = value;
   347→    }
   348→    if (omit_empty_values_ && output.fields().empty()) {
   349→      return ValueUtil::nullValue();
   350→    }
   351→    return ValueUtil::structValue(output);
   352→  }
   353→  ProtobufWkt::Value
   354→  structFormatListCallback(const StructFormatterBase::StructFormatListWrapper& format_list,
   355→                           const StructFormatMapVisitor& visitor) const {
   356→    std::vector<ProtobufWkt::Value> output;
   357→    for (const auto& val : *format_list.value_) {
   358→      ProtobufWkt::Value value = absl::visit(visitor, val);
   359→      if (omit_empty_values_ && value.kind_case() == ProtobufWkt::Value::kNullValue) {
   360→        continue;
   361→      }
   362→      output.push_back(value);
   363→    }
   364→    return ValueUtil::listValue(output);
   365→  }
   366→
   367→  const bool omit_empty_values_;
   368→  const bool preserve_types_;
   369→  const std::string empty_value_;
   370→
   371→  const StructFormatMapWrapper struct_output_format_;
   372→};
   373→
   374→template <class FormatterContext>
   375→using StructFormatterBasePtr = std::unique_ptr<StructFormatterBase<FormatterContext>>;
   376→
   377→template <class FormatterContext>
   378→class JsonFormatterBaseImpl : public FormatterBase<FormatterContext> {
   379→public:
   380→  using CommandParsers = std::vector<CommandParserBasePtr<FormatterContext>>;
   381→
   382→  JsonFormatterBaseImpl(const ProtobufWkt::Struct& format_mapping, bool preserve_types,
   383→                        bool omit_empty_values, bool sort_properties,
   384→                        const CommandParsers& commands = {})
   385→      : struct_formatter_(format_mapping, preserve_types, omit_empty_values, commands),
   386→        sort_properties_(sort_properties) {}
   387→
   388→  // FormatterBase
   389→  std::string formatWithContext(const FormatterContext& context,
   390→                                const StreamInfo::StreamInfo& info) const override {
   391→    const ProtobufWkt::Struct output_struct = struct_formatter_.formatWithContext(context, info);
   392→
   393→    std::string log_line = "";
   394→#ifdef ENVOY_ENABLE_YAML
   395→    if (sort_properties_) {
   396→      log_line = Json::Factory::loadFromProtobufStruct(output_struct)->asJsonString();
   397→    } else {
   398→      log_line = MessageUtil::getJsonStringFromMessageOrError(output_struct, false, true);
   399→    }
   400→#else
   401→    UNREFERENCED_PARAMETER(sort_properties_);
   402→    IS_ENVOY_BUG("Json support compiled out");
   403→#endif
   404→    return absl::StrCat(log_line, "\n");
   405→  }
   406→
   407→private:
   408→  const StructFormatterBase<FormatterContext> struct_formatter_;
   409→  const bool sort_properties_;
   410→};
   411→
   412→using StructFormatter = StructFormatterBase<HttpFormatterContext>;
   413→using StructFormatterPtr = std::unique_ptr<StructFormatter>;
   414→
   415→// Aliases for backwards compatibility.
   416→using FormatterImpl = FormatterBaseImpl<HttpFormatterContext>;
   417→using JsonFormatterImpl = JsonFormatterBaseImpl<HttpFormatterContext>;
   418→
   419→} // namespace Formatter
   420→} // namespace Envoy
